#define GPU_HAS_R2C_CALIB 1

/* Per-pipeline cuFFT floor costs at full GPU utilisation (large batch).
 *
 * Measured on this GPU via: (1) bench_batch.cu sweeping batch=1..65536 for
 * R2C+C2R at each FFT size to get fwd+inv floor, then (2) level_timer.cu
 * measuring the full tree pipeline (fwd + pw_mul + inv + scale) per level
 * at qb=64.  The full-pipeline floor is 1.09-1.15x the fwd+inv floor,
 * because the pointwise multiply adds negligible bandwidth at large batch.
 *
 * These values represent the per-pipeline cost when the GPU is fully
 * saturated — the irreducible compute+bandwidth cost with zero launch
 * overhead.  Used by the batch-aware cost model in estimate_candidate_cost
 * to correctly price tree levels at production q_batch. */
#define GPU_N_FLOOR_SIZES 9
static const int gpu_floor_fft_sizes[GPU_N_FLOOR_SIZES] = {
    128, 256, 512, 1024, 2048, 4096, 8192, 16384, 32768
};
static const double gpu_floor_ns[GPU_N_FLOOR_SIZES] = {
    1.4, 2.5, 4.7, 8.5, 18.3, 38.8, 102.5, 258.8, 675.0
};
#define GPU_HAS_CUFFT_FLOOR 1

#define GPU_SCHOOL_FMA_NS 0.00016773
#define GPU_FFT_OVERHEAD_NS 16.19865991
#define GPU_HBM_BANDWIDTH 3257.57334409
#define GPU_FUSED_MAX_CONV_LEN 8192
#define GPU_PAIRED_CACHED_CORR_RATIO 0.93324059
#define GPU_INDEP_PAIR_RATIO 1.53805991
/* Block build cost: per-block overhead + per-FMA compute.
 * total_ns = nblocks × GPU_BLOCK_BUILD_OVERHEAD_NS
 *          + block_fmas × GPU_BLOCK_BUILD_BASE_FMA_NS
 * Derived from q-batch block_build measurements at B=64 and B=128
 * (n=65536, qb=256).  The per-block overhead (shared mem init,
 * __syncthreads startup, CUDA block scheduling) dominates at small B. */
#define GPU_BLOCK_BUILD_OVERHEAD_NS 1.791
#define GPU_BLOCK_BUILD_BASE_FMA_NS 0.002998
#define GPU_HAS_BLOCK_BUILD_SPLIT 1

/* Legacy single-constant model (used when HAS_BLOCK_BUILD_SPLIT is absent) */
#define GPU_BLOCK_BUILD_NS_PER_FMA 0.00312704
